output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?appointer WHERE {
  wd:Q3522413 wdt:P748 ?appointer
}

args.sparql:
SELECT ?appointer ?label WHERE {
  wd:Q3522413 wdt:P748 ?appointer.
  ?appointer rdfs:label ?label.
  FILTER(LANG(?label) = "en")
}
